  1→#!/usr/bin/env node
  2→
  3→import { readFileSync } from 'fs';
  4→import { Command } from 'commander';
  5→import { initCommand } from './commands/init.js';
  6→import { syncCommand, getTrivialSessions, pruneTrivialSessions } from './commands/sync.js';
  7→import { statusCommand } from './commands/status.js';
  8→import { installHookCommand, uninstallHookCommand } from './commands/install-hook.js';
  9→import { openCommand } from './commands/open.js';
 10→import { dashboardCommand } from './commands/dashboard.js';
 11→import { resetCommand } from './commands/reset.js';
 12→import { statsCommand } from './commands/stats/index.js';
 13→import { configCommand } from './commands/config.js';
 14→import { telemetryCommand } from './commands/telemetry.js';
 15→import { reflectCommand } from './commands/reflect.js';
 16→import { showTelemetryNoticeIfNeeded } from './utils/telemetry.js';
 17→
 18→const pkg = JSON.parse(readFileSync(new URL('../package.json', import.meta.url), 'utf-8'));
 19→
 20→const program = new Command();
 21→
 22→program
 23→  .name('code-insights')
 24→  .description('AI coding session analytics — sync, stats, and insights')
 25→  .version(pkg.version);
 26→
 27→program
 28→  .command('init')
 29→  .description('Set up Code Insights (initializes local database)')
 30→  .action(initCommand);
 31→
 32→const syncCmd = program
 33→  .command('sync')
 34→  .description('Sync AI coding sessions to local SQLite database')
 35→  .option('-f, --force', 'Force re-sync all sessions (also restores hidden sessions)')
 36→  .option('-p, --project <name>', 'Only sync sessions from a specific project')
 37→  .option('-s, --source <name>', 'Only sync sessions from a specific tool (e.g., claude-code, cursor)')
 38→  .option('--dry-run', 'Show what would be synced without making changes')
 39→  .option('-q, --quiet', 'Suppress output (useful for hooks)')
 40→  .option('-v, --verbose', 'Show diagnostic warnings from providers')
 41→  .option('--regenerate-titles', 'Regenerate titles for all sessions')
 42→  .action(syncCommand);
 43→
 44→syncCmd
 45→  .command('prune')
 46→  .description('Soft-delete sessions with ≤2 messages (trivial abandoned sessions)')
 47→  .action(async () => {
 48→    const chalk = (await import('chalk')).default;
 49→    const { default: inquirer } = await import('inquirer');
 50→    console.log(chalk.cyan('\n  Code Insights — Prune\n'));
 51→
 52→    const sessions = getTrivialSessions();
 53→    if (sessions.length === 0) {
 54→      console.log(chalk.green('  No trivial sessions found. Nothing to prune.'));
 55→      return;
 56→    }
 57→
 58→    console.log(chalk.white(`  Found ${sessions.length} session${sessions.length !== 1 ? 's' : ''} with ≤2 messages:\n`));
 59→    for (const s of sessions) {
 60→      const label = s.title ?? chalk.dim('(no title)');
 61→      console.log(`  ${chalk.dim('·')} ${label} ${chalk.dim(`[${s.project_name}, ${s.message_count} msg]`)}`);
 62→    }
 63→    console.log('');
 64→
 65→    const { confirmed } = await inquirer.prompt<{ confirmed: boolean }>([
 66→      {
 67→        type: 'confirm',
 68→        name: 'confirmed',
 69→        message: `Soft-delete these ${sessions.length} session${sessions.length !== 1 ? 's' : ''}? (Restorable with sync --force)`,
 70→        default: false,
 71→      },
 72→    ]);
 73→
 74→    if (!confirmed) {
 75→      console.log(chalk.yellow('\n  Cancelled. No sessions were hidden.'));
 76→      return;
 77→    }
 78→
 79→    const { deleted } = pruneTrivialSessions(sessions.map((s) => s.id));
 80→    console.log(chalk.green(`\n  Hidden ${deleted} session${deleted !== 1 ? 's' : ''}.`));
 81→    console.log(chalk.dim('  Use code-insights sync --force to restore hidden sessions.'));
 82→  });
 83→
 84→program
 85→  .command('status')
 86→  .description('Show Code Insights status and statistics')
 87→  .action(statusCommand);
 88→
 89→program
 90→  .command('install-hook')
 91→  .description('Install Claude Code hook for automatic sync')
 92→  .action(installHookCommand);
 93→
 94→program
 95→  .command('uninstall-hook')
 96→  .description('Remove Claude Code hook')
 97→  .action(uninstallHookCommand);
 98→
 99→program
100→  .command('open')
101→  .description('Open the local dashboard in your browser')
102→  .option('--project', 'Open filtered to the current project')
103→  .action(openCommand);
104→
105→program
106→  .command('dashboard')
107→  .description('Start the Code Insights dashboard server and open in browser')
108→  .option('-p, --port <number>', 'Port number', String(7890))
109→  .option('--no-open', 'Do not open browser automatically')
110→  .action(dashboardCommand);
111→
112→program.addCommand(resetCommand);
113→program.addCommand(statsCommand);
114→program.addCommand(configCommand);
115→program.addCommand(telemetryCommand);
116→program.addCommand(reflectCommand);
117→
118→// Show one-time telemetry disclosure before any command runs
119→showTelemetryNoticeIfNeeded();
120→
121→program.parse();
122→

 1→import { Command } from 'commander';
 2→import { applySharedFlags, parseFlags } from './shared.js';
 3→import type { StatsFlags } from './shared.js';
 4→
 5→// Wrapper that parses flags before calling the action
 6→function wrapAction(actionFn: (flags: StatsFlags) => Promise<void>) {
 7→  return async (options: Record<string, unknown>) => {
 8→    const flags = parseFlags(options);
 9→    await actionFn(flags);
10→  };
11→}
12→
13→// Lazy import actions to avoid loading everything at module load time
14→async function overviewAction(flags: StatsFlags): Promise<void> {
15→  const { overviewAction: action } = await import('./actions/overview.js');
16→  return action(flags);
17→}
18→
19→async function costAction(flags: StatsFlags): Promise<void> {
20→  const { costAction: action } = await import('./actions/cost.js');
21→  return action(flags);
22→}
23→
24→async function projectsAction(flags: StatsFlags): Promise<void> {
25→  const { projectsAction: action } = await import('./actions/projects.js');
26→  return action(flags);
27→}
28→
29→async function todayAction(flags: StatsFlags): Promise<void> {
30→  const { todayAction: action } = await import('./actions/today.js');
31→  return action(flags);
32→}
33→
34→async function modelsAction(flags: StatsFlags): Promise<void> {
35→  const { modelsAction: action } = await import('./actions/models.js');
36→  return action(flags);
37→}
38→
39→async function patternsAction(flags: StatsFlags): Promise<void> {
40→  const { patternsAction: action } = await import('./actions/patterns.js');
41→  return action(flags);
42→}
43→
44→const costCommand = applySharedFlags(
45→  new Command('cost').description('Cost breakdown by project, model, and time period')
46→).action(wrapAction(costAction));
47→
48→const projectsCommand = applySharedFlags(
49→  new Command('projects').description('Per-project detail — sessions, time, cost, models')
50→).action(wrapAction(projectsAction));
51→
52→const todayCommand = applySharedFlags(
53→  new Command('today').description("Today's sessions with titles, duration, cost")
54→).action(wrapAction(todayAction));
55→
56→const modelsCommand = applySharedFlags(
57→  new Command('models').description('Model usage distribution, cost per model, trends')
58→).action(wrapAction(modelsAction));
59→
60→const patternsCommand = applySharedFlags(
61→  new Command('patterns').description('Cross-session patterns — friction, wins, working style')
62→).action(wrapAction(patternsAction));
63→
64→export const statsCommand = applySharedFlags(
65→  new Command('stats')
66→    .description('View usage statistics and analytics')
67→    .addCommand(costCommand)
68→    .addCommand(projectsCommand)
69→    .addCommand(todayCommand)
70→    .addCommand(modelsCommand)
71→    .addCommand(patternsCommand)
72→).action(wrapAction(overviewAction));
