 1→// LLM prompts for cross-session export synthesis.
 2→// Each format has two scope variants (project vs. all).
 3→// The LLM returns raw markdown — no JSON parsing needed.
 4→
 5→export type ExportFormat = 'agent-rules' | 'knowledge-brief' | 'obsidian' | 'notion';
 6→export type ExportScope = 'project' | 'all';
 7→export type ExportDepth = 'essential' | 'standard' | 'comprehensive';
 8→
 9→export const DEPTH_CAPS: Record<ExportDepth, number> = {
10→  essential: 25,
11→  standard: 80,
12→  comprehensive: 200,
13→};
14→
15→// Rough token estimate per insight (title + content + metadata summary).
16→// Used to enforce the hard 60k input token ceiling within the depth cap.
17→const AVG_TOKENS_PER_INSIGHT = 300;
18→const MAX_EXPORT_INPUT_TOKENS = 60000;
19→
20→export interface ExportInsightRow {
21→  id: string;
22→  type: string;
23→  title: string;
24→  content: string;
25→  summary: string;
26→  confidence: number;
27→  project_name: string;
28→  timestamp: string;
29→}
30→
31→export interface ExportContext {
32→  scope: ExportScope;
33→  format: ExportFormat;
34→  depth: ExportDepth;
35→  projectName?: string;    // set when scope === 'project'
36→  sessionCount: number;
37→  projectCount: number;
38→  dateRange: { from: string; to: string };
39→  exportDate: string;      // ISO 8601 date for Obsidian frontmatter
40→}
41→
42→/**
43→ * Apply depth cap and token budget guard, returning the insights to send to the LLM.
44→ * Also returns totalInsights (before cap) for metadata.
45→ */
46→export function applyDepthCap(
47→  insights: ExportInsightRow[],
48→  depth: ExportDepth
49→): { capped: ExportInsightRow[]; totalInsights: number } {
50→  const totalInsights = insights.length;
51→  const depthCap = DEPTH_CAPS[depth];
52→
53→  // Apply depth cap first
54→  let capped = insights.slice(0, depthCap);
55→
56→  // Token budget guard within the depth cap — safety net for unusually large insights
57→  let tokenEstimate = 0;
58→  const tokenBudgeted: ExportInsightRow[] = [];
59→  for (const insight of capped) {
60→    tokenEstimate += AVG_TOKENS_PER_INSIGHT;
61→    if (tokenEstimate > MAX_EXPORT_INPUT_TOKENS) break;
62→    tokenBudgeted.push(insight);
63→  }
64→  capped = tokenBudgeted;
65→
66→  return { capped, totalInsights };
67→}
68→
69→/**
70→ * Format insights for LLM input, grouped by type.
71→ * Includes project_name on each insight for scope-awareness.
72→ */
73→export function buildInsightContext(insights: ExportInsightRow[]): string {
74→  const grouped: Record<string, ExportInsightRow[]> = {};
75→  for (const insight of insights) {
76→    const key = insight.type;
77→    if (!grouped[key]) grouped[key] = [];
78→    grouped[key].push(insight);
79→  }
80→

  1→import * as fs from 'fs';
  2→import * as path from 'path';
  3→import * as os from 'os';
  4→import * as crypto from 'crypto';
  5→import { createRequire } from 'module';
  6→import { PostHog } from 'posthog-node';
  7→import { loadConfig, getConfigDir } from './config.js';
  8→
  9→// PostHog write-only API key (public — this is the standard PostHog pattern;
 10→// write-only keys can only ingest events, not read data).
 11→const POSTHOG_API_KEY = 'REDACTED';
 12→const POSTHOG_HOST = 'https://us.i.posthog.com';
 13→
 14→// Touch file path that tracks whether the disclosure has been shown.
 15→// Content is the CLI version — if version doesn't match current, notice is re-shown.
 16→const NOTICE_FILE = path.join(getConfigDir(), '.telemetry-notice-shown');
 17→
 18→// Exhaustive list of event names — string literal union for autocomplete + typo prevention.
 19→export type TelemetryEventName =
 20→  | 'cli_sync'
 21→  | 'cli_stats'
 22→  | 'cli_dashboard'
 23→  | 'cli_init'
 24→  | 'cli_config'
 25→  | 'cli_reset'
 26→  | 'cli_install_hook'
 27→  | 'cli_status'
 28→  | 'cli_open'
 29→  | 'analysis_run'
 30→  | 'insight_generated'
 31→  | 'export_run'
 32→  | 'dashboard_loaded'
 33→  | 'telemetry_opted_out'
 34→  | 'telemetry_opted_in';
 35→
 36→// PostHog client — lazily initialized on first trackEvent call.
 37→// null when telemetry is disabled or init hasn't happened yet.
 38→let client: PostHog | null = null;
 39→
 40→/**
 41→ * Check if telemetry is enabled.
 42→ *
 43→ * Check order (first match wins):
 44→ * 1. CODE_INSIGHTS_TELEMETRY_DISABLED=1 env var — respects CI/automation opt-out
 45→ * 2. DO_NOT_TRACK=1 env var — respects the community standard
 46→ * 3. config.telemetry field — user's explicit preference
 47→ * 4. Default: true (opt-out model)
 48→ */
 49→export function isTelemetryEnabled(): boolean {
 50→  if (process.env.CODE_INSIGHTS_TELEMETRY_DISABLED === '1') return false;
 51→  if (process.env.DO_NOT_TRACK === '1') return false;
 52→
 53→  const config = loadConfig();
 54→  if (config !== null && typeof config.telemetry === 'boolean') {
 55→    return config.telemetry;
 56→  }
 57→
 58→  return true;
 59→}
 60→
 61→/**
 62→ * Get (or lazily create) the PostHog client.
 63→ * Returns null when telemetry is disabled.
 64→ *
 65→ * flushAt: 1 — flush immediately after each capture(); CLI is short-lived
 66→ * flushInterval: 0 — no background timer; avoids keeping process alive
 67→ */
 68→function getPostHogClient(): PostHog | null {
 69→  if (!isTelemetryEnabled()) return null;
 70→  if (!client) {
 71→    client = new PostHog(POSTHOG_API_KEY, {
 72→      host: POSTHOG_HOST,
 73→      flushAt: 1,
 74→      flushInterval: 0,
 75→    });
 76→  }
 77→  return client;
 78→}
 79→
 80→/**
 81→ * Flush and shut down the PostHog client.
 82→ * Call this in server SIGINT/SIGTERM handlers before process.exit().
 83→ * No-op if telemetry is disabled or client was never initialized.
 84→ */
 85→export async function shutdownTelemetry(): Promise<void> {
 86→  if (client) {
 87→    await client.shutdown();
 88→    client = null;
 89→  }
 90→}
 91→
 92→/**
 93→ * Show the telemetry disclosure notice if it hasn't been shown for this CLI version.
 94→ *
 95→ * Uses a version-stamped touch file at ~/.code-insights/.telemetry-notice-shown.
 96→ * Re-shown when the CLI version changes (catches existing users on upgrades).
 97→ * Only displays if telemetry is enabled.
 98→ *
 99→ * Returns true if the notice was shown.
100→ */
101→export function showTelemetryNoticeIfNeeded(): boolean {
102→  if (!isTelemetryEnabled()) return false;
103→
104→  const currentVersion = getCliVersion();
105→  let shownVersion: string | null = null;
106→
107→  if (fs.existsSync(NOTICE_FILE)) {
108→    try {
109→      shownVersion = fs.readFileSync(NOTICE_FILE, 'utf-8').trim();
110→    } catch {
111→      // Can't read — treat as not shown
112→    }
113→  }
114→
115→  if (shownVersion === currentVersion) return false;
116→
117→  // Show the updated disclosure banner
118→  console.log('');
119→  console.log('  Code Insights collects anonymous usage data to improve the CLI and dashboard.');
120→  console.log('  Includes: commands, page views, OS, CLI version, AI tool types, session counts,');
121→  console.log('  LLM provider, performance timing.');
122→  console.log('  Never includes: file paths, project names, session content, API keys, or personal data.');
123→  console.log('');
124→  console.log('  Disable: code-insights telemetry disable');
125→  console.log('  Details: code-insights telemetry status');
126→  console.log('');
127→
128→  // Write the current version as content — best-effort, non-fatal
129→  try {
130→    const configDir = getConfigDir();
131→    if (!fs.existsSync(configDir)) {
132→      fs.mkdirSync(configDir, { recursive: true, mode: 0o700 });
133→    }
134→    fs.writeFileSync(NOTICE_FILE, currentVersion, { encoding: 'utf-8', mode: 0o600 });
135→  } catch {
136→    // Non-fatal — if we can't write, we'll show the notice again next time
137→  }
138→
139→  return true;
140→}
141→
142→/**
143→ * Classify an error into a structured error_type + error_message pair.
144→ * Used to enrich trackEvent calls and captureError calls with consistent error metadata.
145→ */
146→export function classifyError(error: unknown): { error_type: string; error_message: string } {
147→  if (error instanceof Error) {
148→    if (error.name === 'AbortError') {
149→      return { error_type: 'abort', error_message: error.message };
150→    }
151→    // SyntaxError from JSON.parse
152→    if (error instanceof SyntaxError) {
153→      return { error_type: 'json_parse_error', error_message: error.message };
154→    }
155→    return { error_type: 'api_error', error_message: error.message };
156→  }
157→  return { error_type: 'unknown', error_message: String(error) };
158→}
159→
160→/**
161→ * Parse a Node.js Error.stack into PostHog-compatible stack frames.
162→ * Returns frames in caller-first order (PostHog/Sentry convention).
163→ */
164→function parseStackFrames(stack: string): Array<{
165→  filename: string;
166→  lineno: number;
167→  colno: number;
168→  function: string;
169→  in_app: boolean;
170→}> {
171→  const framePattern = /at\s+(?:(.+?)\s+\()?(.*?):(\d+):(\d+)\)?/g;
172→  const frames: Array<{
173→    filename: string;
174→    lineno: number;
175→    colno: number;
176→    function: string;
177→    in_app: boolean;
178→  }> = [];
179→
180→  let match;
181→  while ((match = framePattern.exec(stack)) !== null) {
182→    const filename = match[2].replace(/^file:\/\//, '');
183→    frames.push({
184→      filename,
185→      lineno: parseInt(match[3], 10),
186→      colno: parseInt(match[4], 10),
187→      function: match[1] || '<anonymous>',
188→      in_app: !filename.includes('node_modules') && !filename.startsWith('node:'),
189→    });
190→  }
191→
192→  return frames;
193→}
194→
195→/**
196→ * Capture an exception in PostHog. Never throws — telemetry must never break the CLI.
197→ * Respects the same opt-out as trackEvent.
198→ *
199→ * @param error - The caught error (or unknown value)
200→ * @param properties - Additional context properties (provider, model, etc.)
201→ */
202→export function captureError(error: unknown, properties?: Record<string, unknown>): void {
203→  const ph = getPostHogClient();
204→  if (!ph) return;
205→
206→  try {
207→    const { error_type, error_message } = classifyError(error);
208→    const exceptionType = error instanceof Error ? error.constructor.name : error_type;
209→    const stack = error instanceof Error && error.stack ? error.stack : '';
210→    const frames = stack ? parseStackFrames(stack) : [];
211→
212→    ph.capture({
213→      distinctId: getStableMachineId(),
214→      event: '$exception',
215→      properties: {
216→        $exception_message: error_message,
217→        $exception_type: exceptionType,
218→        $exception_stack_trace_raw: stack,
219→        $exception_list: [
220→          {
221→            type: exceptionType,
222→            value: error_message,
223→            mechanism: { type: 'generic', handled: true },
224→            ...(frames.length > 0 ? { stacktrace: { frames } } : {}),
225→          },
226→        ],
227→        ...(properties ?? {}),
228→      },
229→    });
230→  } catch {
231→    // Swallow all errors — telemetry failures are silent
232→  }
233→}
234→
235→/**
236→ * Send a telemetry event. Never throws — telemetry must never break the CLI.
237→ *
238→ * @param event - Event name from TelemetryEventName union
239→ * @param properties - Arbitrary event properties (success, duration_ms, etc.)
240→ */
241→export function trackEvent(event: TelemetryEventName, properties?: Record<string, unknown>): void {
242→  const ph = getPostHogClient();
243→  if (!ph) return;
244→
245→  try {
246→    ph.capture({
247→      distinctId: getStableMachineId(),
248→      event,
249→      properties: properties ?? {},
250→    });
251→  } catch {
252→    // Swallow all errors — telemetry failures are silent
253→  }
254→}
