256→/**
257→ * Set person-level properties via PostHog identify().
258→ * Call once after the DB is open (so total_sessions can be queried).
259→ *
260→ * Commands that never open the DB (init, config, telemetry) can skip this —
261→ * PostHog retains person properties from previous calls.
262→ */
263→export async function identifyUser(): Promise<void> {
264→  const ph = getPostHogClient();
265→  if (!ph) return;
266→
267→  try {
268→    const { getDb } = await import('../db/client.js');
269→    const db = getDb();
270→    const row = db.prepare('SELECT COUNT(*) as count FROM sessions').get() as { count: number };
271→
272→    ph.identify({
