318→// Internal helpers
319→// ---------------------------------------------------------------------------
320→
321→/**
322→ * Stable machine ID — does NOT rotate monthly.
323→ *
324→ * Format: SHA-256(hostname:username:code-insights).slice(0, 16)
325→ *
326→ * No PII: hostname and username are never transmitted, only their hash.
327→ * Deterministic: same machine always produces the same ID (survives reinstalls).
328→ */
329→export function getStableMachineId(): string {
330→  let username: string;
331→  try {
332→    username = os.userInfo().username;
333→  } catch {
334→    // os.userInfo() throws in Docker/CI when UID has no /etc/passwd entry
335→    username = `uid-${process.getuid?.() ?? 'unknown'}`;
336→  }
337→
338→  const input = [os.hostname(), username, 'code-insights'].join(':');
339→  return crypto.createHash('sha256').update(input).digest('hex').slice(0, 16);
340→}
341→
342→/**
343→ * Read CLI version from package.json.
344→ */
345→function getCliVersion(): string {
346→  try {
347→    const require = createRequire(import.meta.url);
348→    const pkg = require('../../package.json') as { version: string };
349→    return pkg.version;
350→  } catch {
351→    return 'unknown';
352→  }
353→}
