355→/**
356→ * Detect which AI coding tool data directories exist on this machine.
357→ * Checks directory existence only — never reads file contents.
358→ */
359→function detectProviders(): string[] {
360→  const home = os.homedir();
361→  const detected: string[] = [];
362→
363→  if (fs.existsSync(path.join(home, '.claude', 'projects'))) {
364→    detected.push('claude-code');
365→  }
366→
367→  const cursorStoragePaths = [
368→    path.join(home, 'Library', 'Application Support', 'Cursor', 'User', 'workspaceStorage'),
369→    path.join(home, '.config', 'Cursor', 'User', 'workspaceStorage'),
370→    path.join(home, 'AppData', 'Roaming', 'Cursor', 'User', 'workspaceStorage'),
371→  ];
372→  if (cursorStoragePaths.some((p) => fs.existsSync(p))) {
373→    detected.push('cursor');
374→  }
375→
376→  if (fs.existsSync(path.join(home, '.codex', 'sessions'))) {
377→    detected.push('codex-cli');
378→  }
379→
380→  if (fs.existsSync(path.join(home, '.copilot', 'session-state'))) {
381→    detected.push('copilot-cli');
382→  }
383→
384→  return detected;
385→}
