387→/**
388→ * Check if code-insights is registered as a Claude Code hook.
389→ */
390→function detectHook(): boolean {
391→  try {
392→    const settingsPath = path.join(os.homedir(), '.claude', 'settings.json');
393→    if (!fs.existsSync(settingsPath)) return false;
394→    const content = fs.readFileSync(settingsPath, 'utf-8');
395→    return content.includes('code-insights');
396→  } catch {
397→    return false;
398→  }
